package com.kalyani.car_rental_backend.coupon.controller;import com.kalyani.car_rental_backend.coupon.dto.CouponRequest;import com.kalyani.car_rental_backend.coupon.entity.Coupon;import com.kalyani.car_rental_backend.coupon.repository.CouponRepository;import com.kalyani.car_rental_backend.exception.ResourceNotFoundException;import com.kalyani.car_rental_backend.response.ApiResponse;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.math.*;import java.time.LocalDateTime;import java.util.*;
@RestController @RequestMapping("/coupons")public class CouponController{private final CouponRepository repo;public CouponController(CouponRepository r){repo=r;}@GetMapping public ResponseEntity<ApiResponse<List<Coupon>>>all(){return ResponseEntity.ok(ApiResponse.success(repo.findAll(),"Coupons loaded"));}@PostMapping public ResponseEntity<ApiResponse<Coupon>>create(@Valid@RequestBody CouponRequest r){if(repo.findByCodeIgnoreCase(r.code).isPresent())throw new IllegalArgumentException("Coupon code already exists");var e=new Coupon();apply(e,r);return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(repo.save(e),"Coupon created"));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<Coupon>>update(@PathVariable Long id,@Valid@RequestBody CouponRequest r){var e=repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Coupon not found"));apply(e,r);return ResponseEntity.ok(ApiResponse.success(repo.save(e),"Coupon updated"));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>delete(@PathVariable Long id){repo.deleteById(id);return ResponseEntity.ok(ApiResponse.success(null,"Coupon deleted"));}@GetMapping("/validate/{code}")public ResponseEntity<ApiResponse<Map<String,Object>>>validate(@PathVariable String code,@RequestParam BigDecimal amount){var c=repo.findByCodeIgnoreCase(code).orElseThrow(()->new ResourceNotFoundException("Invalid coupon"));var now=LocalDateTime.now();if(!c.isActive()||(c.getValidFrom()!=null&&now.isBefore(c.getValidFrom()))||(c.getValidUntil()!=null&&now.isAfter(c.getValidUntil())))throw new IllegalArgumentException("Coupon is not active");if(c.getUsageLimit()!=null&&c.getUsedCount()!=null&&c.getUsedCount()>=c.getUsageLimit())throw new IllegalArgumentException("Coupon usage limit reached");if(c.getMinimumAmount()!=null&&amount.compareTo(c.getMinimumAmount())<0)throw new IllegalArgumentException("Minimum booking amount is "+c.getMinimumAmount());BigDecimal d="PERCENT".equals(c.getDiscountType())?amount.multiply(c.getDiscountValue()).divide(BigDecimal.valueOf(100),2,RoundingMode.HALF_UP):c.getDiscountValue();if(c.getMaximumDiscount()!=null&&d.compareTo(c.getMaximumDiscount())>0)d=c.getMaximumDiscount();Map<String,Object>m=new LinkedHashMap<>();m.put("code",c.getCode());m.put("discount",d);m.put("payableAmount",amount.subtract(d).max(BigDecimal.ZERO));return ResponseEntity.ok(ApiResponse.success(m,"Coupon applied"));}private void apply(Coupon e,CouponRequest r){e.setCode(r.code.toUpperCase());e.setDiscountType(r.discountType);e.setDiscountValue(r.discountValue);e.setMinimumAmount(r.minimumAmount);e.setMaximumDiscount(r.maximumDiscount);e.setValidFrom(r.validFrom);e.setValidUntil(r.validUntil);e.setActive(r.active);e.setUsageLimit(r.usageLimit);if(e.getUsedCount()==null)e.setUsedCount(0);}}
